'use client';

import { useEffect, useRef, useState } from 'react';
import type { ComponentType } from 'react';
import { createPortal } from 'react-dom';
import type { LessonRecurrence } from '@soenglish/shared-types';
import { ClipboardCheck, File, FileText, Image, Monitor, Plus, Trash2, Unlink2, X } from 'lucide-react';
import { Button, Field, Tabs } from '../../../components/ui';
import type { LessonFormState, LessonModalMode } from '../types';
import { siteContent } from '../../../mocks';
import type { MockStudent } from '../../../mocks';
import styles from '../../../app/calendar/page.module.scss';

export function LessonModal({
  mode,
  canEdit,
  form,
  onChange,
  onClose,
  onSubmit,
  students,
  canUnlinkSeries,
  onUnlinkSeries,
  canDeleteLesson,
  onDeleteLesson,
}: {
  mode: LessonModalMode;
  canEdit: boolean;
  form: LessonFormState;
  onChange: (next: LessonFormState) => void;
  onClose: () => void;
  onSubmit: () => void;
  students: MockStudent[];
  canUnlinkSeries: boolean;
  onUnlinkSeries: () => void;
  canDeleteLesson: boolean;
  onDeleteLesson: () => void;
}) {
  const text = siteContent.calendar.lessonModal;
  type MaterialKind = 'text' | 'photo' | 'test' | 'file' | 'presentation';
  const [mounted, setMounted] = useState(false);
  const [tab, setTab] = useState<'setup' | 'content'>('setup');
  const [fileError, setFileError] = useState<string | null>(null);
  const [materialsFileStatus, setMaterialsFileStatus] = useState<string | null>(null);
  const [imagePreviewUrl, setImagePreviewUrl] = useState<string | null>(null);
  const materialsFileInputRef = useRef<HTMLInputElement | null>(null);
  const [materialDraft, setMaterialDraft] = useState<{
    kind: MaterialKind;
    text: string;
    files: string[];
  }>({
    kind: 'text',
    text: '',
    files: [],
  });
  const [materialDraftPreviews, setMaterialDraftPreviews] = useState<Array<string | null>>([]);
  const [savedMaterialPreviews, setSavedMaterialPreviews] = useState<Record<string, Array<string | null>>>({});
  const [homeworkPreviews, setHomeworkPreviews] = useState<Array<string | null>>([]);
  const [studentResponsePreviews, setStudentResponsePreviews] = useState<Array<string | null>>([]);
  const weekDayOptions = [
    { value: 1, label: text.weekDays.mon },
    { value: 2, label: text.weekDays.tue },
    { value: 3, label: text.weekDays.wed },
    { value: 4, label: text.weekDays.thu },
    { value: 5, label: text.weekDays.fri },
    { value: 6, label: text.weekDays.sat },
    { value: 7, label: text.weekDays.sun },
  ];
  const filterSafeFiles = (
    files: FileList | null,
  ): { safe: Array<{ name: string; previewUrl: string | null }>; rejected: string[]; maxFileSizeMb: number } => {
    if (!files) return { safe: [], rejected: [], maxFileSizeMb: 5 };
    const allowedMimePrefixes = ['image/', 'application/pdf', 'text/', 'application/vnd', 'application/msword'];
    const allowedExtensions = [
      '.jpg',
      '.jpeg',
      '.png',
      '.webp',
      '.gif',
      '.heic',
      '.heif',
      '.svg',
      '.pdf',
      '.txt',
      '.doc',
      '.docx',
      '.ppt',
      '.pptx',
      '.xls',
      '.xlsx',
    ];
    const maxFileSizeMb = 5;
    const safe: Array<{ name: string; previewUrl: string | null }> = [];
    const rejected: string[] = [];
    Array.from(files).forEach((file) => {
      const lower = file.name.toLowerCase();
      const hasAllowedExt = allowedExtensions.some((ext) => lower.endsWith(ext));
      const hasAllowedMime = allowedMimePrefixes.some((prefix) => file.type.startsWith(prefix));
      const sizeMb = file.size / (1024 * 1024);
      if ((hasAllowedExt || hasAllowedMime) && sizeMb <= maxFileSizeMb) {
        safe.push({
          name: file.name.replace(/[^\w.\-()\s]/g, '_'),
          previewUrl: file.type.startsWith('image/') ? URL.createObjectURL(file) : null,
        });
      } else {
        rejected.push(file.name);
      }
    });
    return { safe, rejected, maxFileSizeMb };
  };
  const formatMessage = (template: string, values: Record<string, string | number>) =>
    Object.entries(values).reduce(
      (acc, [key, value]) => acc.replaceAll(`{${key}}`, String(value)),
      template,
    );
  const getFilePlaceholder = (fileName: string): string => {
    const lower = fileName.toLowerCase();
    if (/\.(pdf)$/.test(lower)) return 'PDF';
    if (/\.(doc|docx|txt)$/.test(lower)) return 'DOC';
    if (/\.(ppt|pptx)$/.test(lower)) return 'PPT';
    if (/\.(xls|xlsx)$/.test(lower)) return 'XLS';
    if (/\.(jpg|jpeg|png|webp|gif|heic|heif|svg)$/.test(lower)) return 'IMG';
    return 'FILE';
  };
  const handleHomeworkFilesSelected = (files: FileList | null) => {
    const { safe, rejected, maxFileSizeMb } = filterSafeFiles(files);
    if (safe.length > 0) {
      onChange({
        ...form,
        homeworkFiles: [...form.homeworkFiles, ...safe.map((item) => item.name)],
      });
      setHomeworkPreviews((prev) => [...prev, ...safe.map((item) => item.previewUrl)]);
    }
    setFileError(
      rejected.length > 0
        ? formatMessage(text.messages.blockedUnsafeFiles, {
            files: rejected.join(', '),
            max: maxFileSizeMb,
          })
        : null,
    );
  };
  const handleStudentResponseFilesSelected = (files: FileList | null) => {
    const { safe, rejected, maxFileSizeMb } = filterSafeFiles(files);
    if (safe.length > 0) {
      onChange({
        ...form,
        studentResponseFiles: [...form.studentResponseFiles, ...safe.map((item) => item.name)],
      });
      setStudentResponsePreviews((prev) => [...prev, ...safe.map((item) => item.previewUrl)]);
    }
    setFileError(
      rejected.length > 0
        ? formatMessage(text.messages.blockedUnsafeFiles, {
            files: rejected.join(', '),
            max: maxFileSizeMb,
          })
        : null,
    );
  };
  const handleMaterialsFilesSelected = (files: FileList | null) => {
    const { safe, rejected, maxFileSizeMb } = filterSafeFiles(files);
    if (safe.length > 0) {
      setMaterialDraft((prev) => ({
        ...prev,
        files: [...prev.files, ...safe.map((item) => item.name)],
      }));
      setMaterialDraftPreviews((prev) => [...prev, ...safe.map((item) => item.previewUrl)]);
    }
    if (rejected.length > 0) {
      setMaterialsFileStatus(formatMessage(text.messages.rejectedFiles, { files: rejected.join(', '), max: maxFileSizeMb }));
    } else {
      setMaterialsFileStatus(null);
    }
  };
  const materialKinds: Array<{ value: MaterialKind; label: string; icon: ComponentType<{ size?: number }> }> = [
    { value: 'text', label: text.materialTypes.text, icon: FileText },
    { value: 'photo', label: text.materialTypes.photo, icon: Image },
    { value: 'test', label: text.materialTypes.test, icon: ClipboardCheck },
    { value: 'file', label: text.materialTypes.file, icon: File },
    { value: 'presentation', label: text.materialTypes.presentation, icon: Monitor },
  ];
  const canSaveMaterial = materialDraft.text.trim().length > 0 || materialDraft.files.length > 0;

  useEffect(() => {
    setMounted(true);
    return () => setMounted(false);
  }, []);

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Escape') setImagePreviewUrl(null);
    };
    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, []);

  if (!mounted) return null;

  return createPortal(
    <div className={styles.modalOverlay} onClick={onClose}>
      <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
        <div className={styles.modalHeader}>
          <div>
            <div className={styles.modalTitle}>{mode === 'create' ? text.titleCreate : text.titleEdit}</div>
            <div className={styles.modalSubtitle}>{text.subtitle}</div>
          </div>
          <div className={styles.modalHeaderActions}>
            {canUnlinkSeries ? (
              <button
                type="button"
                aria-label={text.aria.unlinkSeries}
                title="Unlink series"
                className={styles.modalIconBtn}
                onClick={onUnlinkSeries}
              >
                <Unlink2 size={16} />
              </button>
            ) : null}
            {canDeleteLesson ? (
              <button
                type="button"
                aria-label={text.aria.deleteLesson}
                title="Delete lesson"
                className={`${styles.modalIconBtn} ${styles.modalIconBtnDanger}`}
                onClick={onDeleteLesson}
              >
                <Trash2 size={16} />
              </button>
            ) : null}
            <button type="button" aria-label={text.aria.closeModal} className={styles.modalCloseBtn} onClick={onClose}>
              ×
            </button>
          </div>
        </div>
        <div className={styles.modalScroll}>
          <Tabs
            value={tab}
            onValueChange={setTab}
            ariaLabel={text.aria.sections}
            className={styles.modalTabsRoot}
            listClassName={styles.modalTabsList}
            triggerClassName={styles.modalTabsTrigger}
            activeTriggerClassName={styles.modalTabsTriggerActive}
            panelClassName={styles.modalTabsPanel}
            items={[
              {
                value: 'setup',
                label: text.sections.setup,
                panel: (
                  <div className={`${styles.modalFieldsGrid} ${styles.modalSetupGrid}`}>
                    <div className={styles.fieldGroup}>
                      <label className={styles.fieldLabel}>{text.fields.title}</label>
                      <Field className={styles.fieldInput} value={form.title} disabled={!canEdit} onChange={(e) => onChange({ ...form, title: e.target.value })} />
                    </div>
                    <div className={styles.fieldGroup}>
                      <label className={styles.fieldLabel}>{text.fields.type}</label>
                      <Field as="select" className={styles.fieldInput} value={form.type} disabled={!canEdit} onChange={(e) => onChange({ ...form, type: e.target.value as LessonFormState['type'] })}>
                        <option value="grammar">{text.options.grammar}</option>
                        <option value="vocabulary">{text.options.vocabulary}</option>
                        <option value="speaking">{text.options.speaking}</option>
                        <option value="listening">{text.options.listening}</option>
                      </Field>
                    </div>
                    <div className={styles.fieldGroup}>
                      <label className={styles.fieldLabel}>{text.fields.date}</label>
                      <Field type="date" className={styles.fieldInput} value={form.date} disabled={!canEdit} onChange={(e) => onChange({ ...form, date: e.target.value })} />
                    </div>
                    <div className={styles.fieldGroup}>
                      <label className={styles.fieldLabel}>{text.fields.startTime}</label>
                      <Field type="time" className={styles.fieldInput} value={form.startTime} disabled={!canEdit} onChange={(e) => onChange({ ...form, startTime: e.target.value })} />
                    </div>
                    <div className={styles.fieldGroup}>
                      <label className={styles.fieldLabel}>{text.fields.duration}</label>
                      <Field type="number" className={styles.fieldInput} min={55} step={5} value={String(form.duration)} disabled={!canEdit} onChange={(e) => onChange({ ...form, duration: Math.max(55, Number(e.target.value) || 55) })} />
                    </div>
                    <div className={styles.fieldGroup}>
                      <label className={styles.fieldLabel}>{text.fields.recurrence}</label>
                      <Field as="select" className={styles.fieldInput} value={form.recurrence} disabled={!canEdit} onChange={(e) => onChange({ ...form, recurrence: e.target.value as LessonRecurrence })}>
                        <option value="none">{text.options.noRepeat}</option>
                        <option value="daily">{text.options.daily}</option>
                        <option value="weekly">{text.options.weekly}</option>
                        <option value="monthly">{text.options.monthly}</option>
                      </Field>
                    </div>
                    <div className={styles.fieldGroup}>
                      <label className={styles.fieldLabel}>{text.fields.status}</label>
                      <Field as="select" className={styles.fieldInput} value={form.status} disabled={!canEdit} onChange={(e) => onChange({ ...form, status: e.target.value as LessonFormState['status'], cancelReason: e.target.value === 'cancelled' ? form.cancelReason : undefined })}>
                        <option value="planned">{text.options.planned}</option>
                        <option value="completed">{text.options.completed}</option>
                        <option value="cancelled">{text.options.cancelled}</option>
                      </Field>
                    </div>
                    {form.status === 'cancelled' ? (
                      <div className={styles.fieldGroup}>
                        <label className={styles.fieldLabel}>{text.fields.cancelReason}</label>
                        <Field as="select" className={styles.fieldInput} value={form.cancelReason ?? 'student_absent'} disabled={!canEdit} onChange={(e) => onChange({ ...form, cancelReason: e.target.value as NonNullable<LessonFormState['cancelReason']> })}>
                          <option value="student_absent">{text.options.studentAbsent}</option>
                          <option value="student_requested_cancel">{text.options.studentRequestedCancel}</option>
                          <option value="teacher_absent">{text.options.teacherAbsent}</option>
                        </Field>
                      </div>
                    ) : null}
                    <div className={styles.fieldGroup}>
                      <label className={styles.fieldLabel}>{text.fields.credited}</label>
                      <Field as="select" className={styles.fieldInput} value={form.credited ? 'yes' : 'no'} disabled={!canEdit} onChange={(e) => onChange({ ...form, credited: e.target.value === 'yes' })}>
                        <option value="yes">{text.options.credited}</option>
                        <option value="no">{text.options.notCredited}</option>
                      </Field>
                    </div>
                    {form.recurrence === 'weekly' ? (
                      <div className={styles.fieldGroup}>
                        <label className={styles.fieldLabel}>{text.fields.weekDays}</label>
                        <div className={styles.weekDaysRow}>
                          {weekDayOptions.map((day) => {
                            const selected = form.weeklyDays.includes(day.value);
                            return (
                              <button
                                key={day.value}
                                type="button"
                                className={`${styles.weekDayChip} ${selected ? styles.weekDayChipActive : ''}`}
                                onClick={() => {
                                  const next = selected
                                    ? form.weeklyDays.filter((weekday) => weekday !== day.value)
                                    : [...form.weeklyDays, day.value];
                                  onChange({ ...form, weeklyDays: next.sort((a, b) => a - b) });
                                }}
                              >
                                {day.label}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                    ) : null}
                    <div className={styles.fieldGroup}>
                      <label className={styles.fieldLabel}>{text.fields.student}</label>
                      <Field as="select" className={styles.fieldInput} value={form.studentId} disabled={!canEdit} onChange={(e) => {
                        const nextStudent = students.find((student) => student.id === e.target.value);
                        if (!nextStudent) return;
                        onChange({
                          ...form,
                          studentId: nextStudent.id,
                          studentName: nextStudent.fullName,
                        });
                      }}>
                        {students.map((student) => (
                          <option key={student.id} value={student.id}>
                            {student.fullName}
                          </option>
                        ))}
                      </Field>
                    </div>
                  </div>
                ),
              },
              {
                value: 'content',
                label: text.sections.content,
                panel: (
                  <>
                    <div className={`${styles.fieldGroup} ${styles.fieldGroupFull} ${styles.modalSectionCard}`}>
            <label className={styles.fieldLabel}>{text.fields.lessonPlan}</label>
            <Field
              as="textarea"
              className={styles.fieldInput}
              rows={4}
              value={form.lessonPlan}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...form, lessonPlan: e.target.value })}
            />
          </div>
          <div className={`${styles.fieldGroup} ${styles.fieldGroupFull} ${styles.modalSectionCard} ${styles.materialsCard}`}>
            <div className={styles.materialsHeader}>
              <label className={styles.fieldLabel}>{text.fields.materials}</label>
              <div className={styles.materialsHint}>{text.materialsHint}</div>
            </div>
            <div className={styles.materialTypeRow}>
              {materialKinds.map((kind) => {
                const Icon = kind.icon;
                const isActive = materialDraft.kind === kind.value;
                return (
                  <button
                    key={kind.value}
                    type="button"
                    className={`${styles.materialTypeBtn} ${isActive ? styles.materialTypeBtnActive : ''}`}
                    disabled={!canEdit}
                    onClick={() => setMaterialDraft((prev) => ({ ...prev, kind: kind.value }))}
                  >
                    <Icon size={14} />
                    <span>{kind.label}</span>
                  </button>
                );
              })}
            </div>
            <div className={styles.materialEditorCard}>
              <Field
                as="textarea"
                className={styles.fieldInput}
                rows={3}
                placeholder={text.placeholders.addText}
                value={materialDraft.text}
                disabled={!canEdit}
                onChange={(e) => setMaterialDraft((prev) => ({ ...prev, text: e.target.value }))}
              />
              <Field
                type="file"
                multiple
                ref={materialsFileInputRef}
                style={{ display: 'none' }}
                disabled={!canEdit}
                onChange={(e) => {
                  handleMaterialsFilesSelected(e.target.files);
                  e.currentTarget.value = '';
                }}
              />
              <button
                type="button"
                className={styles.fileButton}
                disabled={!canEdit}
                onClick={() => materialsFileInputRef.current?.click()}
              >
                <span>{text.actions.addFile}</span>
              </button>
              {materialsFileStatus ? <div className={styles.materialsFileStatus}>{materialsFileStatus}</div> : null}
              {materialDraft.files.length > 0 ? (
                <div className={styles.fileGrid}>
                  {materialDraft.files.map((fileName, fileIndex) => (
                    <div
                      key={`draft-${fileName}-${fileIndex}`}
                      className={`${styles.fileChip} ${materialDraftPreviews[fileIndex] ? styles.fileChipImage : ''}`}
                      style={
                        materialDraftPreviews[fileIndex]
                          ? { backgroundImage: `url(${materialDraftPreviews[fileIndex]})` }
                          : undefined
                      }
                    >
                      <button
                        type="button"
                        className={styles.fileChipRemove}
                        aria-label={text.aria.removeFile}
                        onClick={() => {
                          setMaterialDraft((prev) => ({
                            ...prev,
                            files: prev.files.filter((_, idx) => idx !== fileIndex),
                          }));
                          setMaterialDraftPreviews((prev) => {
                            return prev.filter((_, idx) => idx !== fileIndex);
                          });
                        }}
                      >
                        ×
                      </button>
                      <span>{fileName}</span>
                      {!materialDraftPreviews[fileIndex] ? (
                        <em className={styles.fileChipType}>{getFilePlaceholder(fileName)}</em>
                      ) : null}
                    </div>
                  ))}
                </div>
              ) : null}
              <Button
                type="button"
                className={styles.saveMaterialBtn}
                disabled={!canEdit || !canSaveMaterial}
                onClick={() => {
                  if (!canSaveMaterial) return;
                  const newMaterialId = `mat-${Date.now()}`;
                  onChange({
                    ...form,
                    materials: [
                      ...form.materials,
                      {
                        id: newMaterialId,
                        kind: materialDraft.kind,
                        text: materialDraft.text.trim(),
                        files: materialDraft.files,
                      },
                    ],
                  });
                  setSavedMaterialPreviews((prev) => ({
                    ...prev,
                    [newMaterialId]: materialDraftPreviews,
                  }));
                  setMaterialDraft({ kind: materialDraft.kind, text: '', files: [] });
                  setMaterialDraftPreviews([]);
                }}
              >
                <Plus size={14} />
                <span>{text.actions.saveMaterial}</span>
              </Button>
            </div>
            {form.materials.length === 0 ? (
              <div className={styles.materialsEmpty}>{text.noMaterials}</div>
            ) : (
              <div className={styles.savedMaterialsList}>
                {form.materials.map((material) => {
                  const kindMeta = materialKinds.find((kind) => kind.value === material.kind);
                  const KindIcon = kindMeta?.icon ?? FileText;
                  return (
                    <div key={material.id} className={styles.savedMaterialItem}>
                      <div className={styles.savedMaterialMeta}>
                        <KindIcon size={14} />
                        <strong>{kindMeta?.label ?? text.fallbackMaterialLabel}</strong>
                      </div>
                      <button
                        type="button"
                        aria-label={text.aria.removeMaterial}
                        className={styles.materialRemoveBtn}
                        onClick={() => {
                          onChange({
                            ...form,
                            materials: form.materials.filter((item) => item.id !== material.id),
                          });
                          setSavedMaterialPreviews((prev) => {
                            const next = { ...prev };
                            delete next[material.id];
                            return next;
                          });
                        }}
                      >
                        <X size={14} />
                      </button>
                      {material.text ? <div className={styles.savedMaterialText}>{material.text}</div> : null}
                      {material.files.length > 0 ? (
                        <div className={styles.fileGrid}>
                          {material.files.map((fileName, fileIndex) => (
                            <div
                              key={`${material.id}-${fileName}-${fileIndex}`}
                              className={`${styles.fileChip} ${savedMaterialPreviews[material.id]?.[fileIndex] ? styles.fileChipImage : ''}`}
                              style={
                                savedMaterialPreviews[material.id]?.[fileIndex]
                                  ? { backgroundImage: `url(${savedMaterialPreviews[material.id][fileIndex]})` }
                                  : undefined
                              }
                              role={savedMaterialPreviews[material.id]?.[fileIndex] ? 'button' : undefined}
                              tabIndex={savedMaterialPreviews[material.id]?.[fileIndex] ? 0 : -1}
                              onClick={() => {
                                const preview = savedMaterialPreviews[material.id]?.[fileIndex];
                                if (preview) setImagePreviewUrl(preview);
                              }}
                              onKeyDown={(event) => {
                                if (event.key !== 'Enter' && event.key !== ' ') return;
                                const preview = savedMaterialPreviews[material.id]?.[fileIndex];
                                if (preview) setImagePreviewUrl(preview);
                              }}
                            >
                              <span>{fileName}</span>
                              {!savedMaterialPreviews[material.id]?.[fileIndex] ? (
                                <em className={styles.fileChipType}>{getFilePlaceholder(fileName)}</em>
                              ) : null}
                            </div>
                          ))}
                        </div>
                      ) : null}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
          <div className={`${styles.fieldGroup} ${styles.fieldGroupFull} ${styles.modalSectionCard} ${styles.homeworkCard}`}>
            <label className={styles.fieldLabel}>{text.fields.homework}</label>
            <Field
              as="textarea"
              className={styles.fieldInput}
              rows={4}
              value={form.homeworkText}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...form, homeworkText: e.target.value })}
            />
            <Field
              as="file-button"
              className={styles.fileButton}
              buttonLabel={text.actions.addFile}
              multiple
              disabled={!canEdit}
              onFilesSelected={handleHomeworkFilesSelected}
            />
            {form.homeworkFiles.length > 0 ? (
              <div className={styles.fileGrid}>
                {form.homeworkFiles.map((fileName, fileIndex) => (
                  <div
                    key={`hw-${fileName}-${fileIndex}`}
                    className={`${styles.fileChip} ${homeworkPreviews[fileIndex] ? styles.fileChipImage : ''}`}
                    style={
                      homeworkPreviews[fileIndex]
                        ? { backgroundImage: `url(${homeworkPreviews[fileIndex]})` }
                        : undefined
                    }
                    role={homeworkPreviews[fileIndex] ? 'button' : undefined}
                    tabIndex={homeworkPreviews[fileIndex] ? 0 : -1}
                    onClick={() => {
                      const preview = homeworkPreviews[fileIndex];
                      if (preview) setImagePreviewUrl(preview);
                    }}
                  >
                    <button
                      type="button"
                      className={styles.fileChipRemove}
                      aria-label={text.aria.removeFile}
                      onClick={(event) => {
                        event.stopPropagation();
                        onChange({
                          ...form,
                          homeworkFiles: form.homeworkFiles.filter((_, idx) => idx !== fileIndex),
                        });
                        setHomeworkPreviews((prev) => prev.filter((_, idx) => idx !== fileIndex));
                      }}
                    >
                      ×
                    </button>
                    <span>{fileName}</span>
                    {!homeworkPreviews[fileIndex] ? (
                      <em className={styles.fileChipType}>{getFilePlaceholder(fileName)}</em>
                    ) : null}
                  </div>
                ))}
              </div>
            ) : null}
          </div>
          <div className={`${styles.fieldGroup} ${styles.fieldGroupFull} ${styles.modalSectionCard} ${styles.studentResponseCard}`}>
            <label className={styles.fieldLabel}>{text.fields.studentResponse}</label>
            <Field
              as="textarea"
              className={styles.fieldInput}
              rows={4}
              value={form.studentResponseText}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...form, studentResponseText: e.target.value })}
            />
            <Field
              as="file-button"
              className={styles.fileButton}
              buttonLabel={text.actions.addFile}
              multiple
              disabled={!canEdit}
              onFilesSelected={handleStudentResponseFilesSelected}
            />
            {form.studentResponseFiles.length > 0 ? (
              <div className={styles.fileGrid}>
                {form.studentResponseFiles.map((fileName, fileIndex) => (
                  <div
                    key={`resp-${fileName}-${fileIndex}`}
                    className={`${styles.fileChip} ${studentResponsePreviews[fileIndex] ? styles.fileChipImage : ''}`}
                    style={
                      studentResponsePreviews[fileIndex]
                        ? { backgroundImage: `url(${studentResponsePreviews[fileIndex]})` }
                        : undefined
                    }
                    role={studentResponsePreviews[fileIndex] ? 'button' : undefined}
                    tabIndex={studentResponsePreviews[fileIndex] ? 0 : -1}
                    onClick={() => {
                      const preview = studentResponsePreviews[fileIndex];
                      if (preview) setImagePreviewUrl(preview);
                    }}
                  >
                    <button
                      type="button"
                      className={styles.fileChipRemove}
                      aria-label={text.aria.removeFile}
                      onClick={(event) => {
                        event.stopPropagation();
                        onChange({
                          ...form,
                          studentResponseFiles: form.studentResponseFiles.filter((_, idx) => idx !== fileIndex),
                        });
                        setStudentResponsePreviews((prev) => prev.filter((_, idx) => idx !== fileIndex));
                      }}
                    >
                      ×
                    </button>
                    <span>{fileName}</span>
                    {!studentResponsePreviews[fileIndex] ? (
                      <em className={styles.fileChipType}>{getFilePlaceholder(fileName)}</em>
                    ) : null}
                  </div>
                ))}
              </div>
            ) : null}
          </div>
                  </>
                ),
              },
            ]}
          />
          {fileError ? <div className={styles.fileError}>{fileError}</div> : null}
        </div>
        <div className={styles.modalActions}>
          <Button type="button" className={styles.modalCancelBtn} onClick={onClose}>
            {text.actions.cancel}
          </Button>
          <Button type="button" className={styles.modalConfirmBtn} onClick={onSubmit} disabled={!canEdit}>
            {canEdit
              ? mode === 'create'
                ? text.actions.saveLesson
                : text.actions.updateLesson
              : text.actions.sendChangeRequest}
          </Button>
        </div>
      </div>
      {imagePreviewUrl ? (
        <div
          className={styles.imagePreviewOverlay}
          onClick={() => setImagePreviewUrl(null)}
        >
          <div
            className={styles.imagePreviewModal}
            onClick={(event) => event.stopPropagation()}
          >
            <button
              type="button"
              className={styles.imagePreviewClose}
              aria-label={text.aria.closeImagePreview}
              onClick={() => setImagePreviewUrl(null)}
            >
              ×
            </button>
            <img src={imagePreviewUrl} alt={text.imagePreviewAlt} className={styles.imagePreviewImg} />
          </div>
        </div>
      ) : null}
    </div>,
    document.body,
  );
}

