'use client';

import { useEffect, useMemo, useRef, useState } from 'react';
import type { ScheduledLessonDto } from '@soenglish/shared-types';
import { PageHeader } from '../../components/ui';
import { activeMockUser, canSchedule, canView, getVisibleStudents, siteContent } from '../../mocks';
import { CalendarHeaderControls, CalendarMonthNavigator, SelectedDateSidebar } from './sections';
import { readLessonDragPayload, writeLessonDragPayload } from '../../features/calendar/dnd/dragPayload';
import {
  calculateEndTime,
  fromLessonFormState,
  toLessonFormState,
} from '../../features/calendar/adapters/lessonCalendarAdapter';
import { hasTimeConflict, isPastSlot } from '../../features/calendar/rules/conflicts';
import { LessonModal } from '../../features/calendar/ui/LessonModal';
import { useLessonCalendarState } from '../../features/calendar/ui/useLessonCalendarState';
import type { LessonFormState, LessonModalMode } from '../../features/calendar/types';
import styles from './page.module.scss';

const MONTHS = [
  'January',
  'February',
  'March',
  'April',
  'May',
  'June',
  'July',
  'August',
  'September',
  'October',
  'November',
  'December',
];
const DAYS = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

function toDateString(date: Date): string {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(
    date.getDate(),
  ).padStart(2, '0')}`;
}

function isDateBeforeToday(dateStr: string): boolean {
  const today = toDateString(new Date());
  return dateStr < today;
}

function isLessonInPast(lesson: ScheduledLessonDto): boolean {
  return new Date(`${lesson.date}T${lesson.startTime}:00`).getTime() < Date.now();
}

export default function CalendarPage() {
  if (!canView('calendar', activeMockUser.role)) return null;
  const {
    lessons,
    setLessons,
    role,
    setRole,
    view,
    setView,
    selectedDate,
    setSelectedDate,
    visibleLessons,
  } = useLessonCalendarState(activeMockUser.role, activeMockUser.id);
  const [year, setYear] = useState(2026);
  const [month, setMonth] = useState(3);
  const [modalMode, setModalMode] = useState<LessonModalMode>('create');
  const [editingLesson, setEditingLesson] = useState<ScheduledLessonDto | null>(null);
  const [form, setForm] = useState<LessonFormState | null>(null);
  const canManage = canSchedule('calendar', role);
  const visibleStudents = useMemo(
    () => getVisibleStudents(role, activeMockUser.id),
    [role],
  );

  const lessonsOnDate = (date: string) => visibleLessons.filter((lesson) => lesson.date === date);
  const selectedLessons = selectedDate ? lessonsOnDate(selectedDate) : [];
  const daysCount = new Date(year, month + 1, 0).getDate();
  const firstDow = ((new Date(year, month, 1).getDay() + 6) % 7) as number;
  const today = toDateString(new Date());
  const now = new Date();
  const nowMinutes = now.getHours() * 60 + now.getMinutes();

  const weekStart = (() => {
    const base = selectedDate ? new Date(selectedDate) : new Date(year, month, 1);
    const dow = base.getDay() === 0 ? 6 : base.getDay() - 1;
    const start = new Date(base);
    start.setDate(base.getDate() - dow);
    return start;
  })();
  const weekDays = Array.from({ length: 7 }, (_, i) => {
    const date = new Date(weekStart);
    date.setDate(weekStart.getDate() + i);
    return date;
  });
  const startHour = 8;
  const endHour = 20;
  const minutesPerDay = (endHour - startHour) * 60;
  const pxPerMinute = 1.2;
  const dayColumnHeight = minutesPerDay * pxPerMinute;
  const hourMarks = Array.from({ length: endHour - startHour + 1 }, (_, i) => i + startHour);

  const [resizeState, setResizeState] = useState<{
    lessonId: string;
    edge: 'top' | 'bottom';
    originY: number;
    initialStart: string;
    initialDuration: number;
  } | null>(null);
  const lessonsRef = useRef(lessons);
  const [draggingLessonId, setDraggingLessonId] = useState<string | null>(null);
  const resizedRef = useRef(false);
  const previewResizeRef = useRef<{ lessonId: string; startTime: string; duration: number } | null>(null);
  const suppressDragRef = useRef(false);
  const [monthGhostDate, setMonthGhostDate] = useState<string | null>(null);
  const [weekGhost, setWeekGhost] = useState<{
    lessonId: string;
    date: string;
    startTime: string;
    duration: number;
    type: ScheduledLessonDto['type'];
    title: string;
  } | null>(null);
  const [conflictDialog, setConflictDialog] = useState<{
    open: boolean;
    title: string;
    message?: string;
    date: string;
    startTime: string;
    endTime: string;
    excludeLessonId?: string;
  } | null>(null);
  const [warningDialog, setWarningDialog] = useState<{ open: boolean; title: string; message: string } | null>(
    null,
  );
  const [confirmDeleteOpen, setConfirmDeleteOpen] = useState(false);
  const [confirmUnlinkOpen, setConfirmUnlinkOpen] = useState(false);
  useEffect(() => {
    lessonsRef.current = lessons;
  }, [lessons]);

  const typeColor: Record<string, string> = {
    grammar: 'Blue',
    vocabulary: 'Green',
    speaking: 'Amber',
    listening: 'Purple',
  };
  const typeLabel: Record<string, string> = {
    grammar: 'Grammar',
    vocabulary: 'Vocabulary',
    speaking: 'Speaking',
    listening: 'Listening',
  };
  const getConflictingLessons = (params: {
    date: string;
    startTime: string;
    endTime: string;
    excludeLessonId?: string;
  }) => {
    const toMinutes = (time: string) => {
      const [hour, minute] = time.split(':').map(Number);
      return hour * 60 + minute;
    };
    const candidateStart = toMinutes(params.startTime);
    const candidateEnd = toMinutes(params.endTime);
    return lessons
      .filter((lesson) => lesson.date === params.date && lesson.id !== params.excludeLessonId)
      .filter((lesson) => {
        const lessonStart = toMinutes(lesson.startTime);
        const lessonEnd = toMinutes(lesson.endTime);
        return candidateStart < lessonEnd && candidateEnd > lessonStart;
      })
      .sort((a, b) => a.startTime.localeCompare(b.startTime));
  };

  const openCreateModal = (date: string, startTime = '10:00') => {
    setModalMode('create');
    setEditingLesson(null);
    setForm({
      title: 'New lesson',
      type: 'grammar',
      date,
      startTime,
      duration: 55,
      teacherId: activeMockUser.id,
      teacherName: activeMockUser.fullName,
      studentId: activeMockUser.role === 'student' ? activeMockUser.id : 'student-1',
      studentName: activeMockUser.role === 'student' ? activeMockUser.fullName : 'Mykola K.',
      notes: '',
      lessonPlan: '',
      materials: [],
      homeworkText: '',
      homeworkFiles: [],
      studentResponseText: '',
      studentResponseFiles: [],
      status: 'planned',
      credited: false,
      recurrence: 'none',
      weeklyDays: [],
      applyToSeries: false,
    });
  };

  const openEditModal = (lesson: ScheduledLessonDto) => {
    setModalMode('edit');
    setEditingLesson(lesson);
    setForm(toLessonFormState(lesson));
  };

  const closeModal = () => {
    setForm(null);
    setEditingLesson(null);
  };

  const applyLessonUpdate = (nextLesson: ScheduledLessonDto, sourceLesson?: ScheduledLessonDto) => {
    if (hasTimeConflict(lessons, nextLesson, sourceLesson?.id)) {
      setConflictDialog({
        open: true,
        title: 'Time slot is busy',
        message: 'You cannot create or move a lesson to this time because another lesson already exists.',
        date: nextLesson.date,
        startTime: nextLesson.startTime,
        endTime: nextLesson.endTime,
        excludeLessonId: sourceLesson?.id,
      });
      return;
    }
    if (isPastSlot(nextLesson.date, nextLesson.startTime)) {
      setWarningDialog({
        open: true,
        title: 'Cannot schedule in the past',
        message: 'You cannot create or move a lesson to a past date or time.',
      });
      return;
    }
    if (!sourceLesson) {
      setLessons((prev) => [...prev, nextLesson]);
      return;
    }
    if (form?.applyToSeries && sourceLesson.seriesId) {
      setLessons((prev) =>
        prev.map((lesson) =>
          lesson.seriesId === sourceLesson.seriesId
            ? {
                ...lesson,
                title: nextLesson.title,
                type: nextLesson.type,
                duration: nextLesson.duration,
                recurrence: nextLesson.recurrence,
                weeklyDays: nextLesson.weeklyDays,
                notes: nextLesson.notes,
                startTime: nextLesson.startTime,
                endTime: nextLesson.endTime,
              }
            : lesson,
        ),
      );
      return;
    }
    setLessons((prev) => prev.map((lesson) => (lesson.id === sourceLesson.id ? nextLesson : lesson)));
  };

  const submitModal = () => {
    if (!form) return;
    const candidate = fromLessonFormState(form, editingLesson ?? undefined);
    if (!canManage) candidate.status = 'planned';
    applyLessonUpdate(candidate, editingLesson ?? undefined);
    if (!editingLesson && form.recurrence === 'weekly' && form.weeklyDays.length > 0) {
      const baseDate = new Date(form.date);
      form.weeklyDays.forEach((weekday, index) => {
        if (index === 0) return;
        const delta = (weekday - (baseDate.getDay() === 0 ? 7 : baseDate.getDay()) + 7) % 7;
        const nextDate = new Date(baseDate);
        nextDate.setDate(baseDate.getDate() + delta);
        applyLessonUpdate(
          {
            ...candidate,
            id: `${candidate.id}-${weekday}`,
            date: toDateString(nextDate),
          },
          undefined,
        );
      });
    }
    closeModal();
  };

  const moveLesson = (lessonId: string, date: string, startTime?: string) => {
    setLessons((prev) =>
      prev.map((lesson) => {
        if (lesson.id !== lessonId) return lesson;
        const nextStart = startTime ?? lesson.startTime;
        const next = {
          ...lesson,
          date,
          startTime: nextStart,
          endTime: calculateEndTime(nextStart, lesson.duration),
          status: canManage ? lesson.status : 'planned',
        };
        if (hasTimeConflict(prev, next, lesson.id) || isPastSlot(date, nextStart)) return lesson;
        return next;
      }),
    );
  };

  const weekLessons = useMemo(
    () =>
      visibleLessons.filter((lesson) => {
        const d = new Date(lesson.date);
        return d >= weekDays[0] && d <= weekDays[6];
      }),
    [visibleLessons, weekDays],
  );
  const handleResizeMove = (event: MouseEvent) => {
    if (!resizeState) return;
    const deltaMinutes = Math.round((event.clientY - resizeState.originY) / (pxPerMinute * 15)) * 15;
    resizedRef.current = true;
    setLessons((prev) =>
      prev.map((lesson) => {
        if (lesson.id !== resizeState.lessonId) return lesson;
        let nextDuration = resizeState.initialDuration;
        let nextStart = resizeState.initialStart;
        if (resizeState.edge === 'bottom') {
          nextDuration = Math.max(55, resizeState.initialDuration + deltaMinutes);
        } else {
          const [h, m] = resizeState.initialStart.split(':').map(Number);
          const startMinutes = h * 60 + m + deltaMinutes;
          const bounded = Math.max(startHour * 60, Math.min(startMinutes, h * 60 + m + resizeState.initialDuration - 55));
          const newH = Math.floor(bounded / 60);
          const newM = bounded % 60;
          nextStart = `${String(newH).padStart(2, '0')}:${String(newM).padStart(2, '0')}`;
          nextDuration = resizeState.initialDuration - (bounded - (h * 60 + m));
        }
        previewResizeRef.current = { lessonId: lesson.id, startTime: nextStart, duration: nextDuration };
        return {
          ...lesson,
          startTime: nextStart,
          duration: nextDuration,
          endTime: calculateEndTime(nextStart, nextDuration),
        };
      }),
    );
  };

  const stopResize = () => {
    const preview = previewResizeRef.current;
    if (preview) {
      setLessons((prev) =>
        prev.map((lesson) => {
          if (lesson.id !== preview.lessonId) return lesson;
          const next = {
            ...lesson,
            startTime: preview.startTime,
            duration: preview.duration,
            endTime: calculateEndTime(preview.startTime, preview.duration),
          status: canManage ? lesson.status : 'planned',
          };
          if (hasTimeConflict(prev, next, lesson.id) || isPastSlot(next.date, next.startTime)) {
            if (hasTimeConflict(prev, next, lesson.id)) {
              setConflictDialog({
                open: true,
                title: 'Time slot is busy',
                message: 'Another lesson already exists for this time.',
                date: next.date,
                startTime: next.startTime,
                endTime: next.endTime,
                excludeLessonId: lesson.id,
              });
            } else {
              setWarningDialog({
                open: true,
                title: 'Cannot resize into past time',
                message: 'Lesson duration cannot be changed into a past time slot.',
              });
            }
            return {
              ...lesson,
              startTime: resizeState?.initialStart ?? lesson.startTime,
              duration: resizeState?.initialDuration ?? lesson.duration,
              endTime: calculateEndTime(
                resizeState?.initialStart ?? lesson.startTime,
                resizeState?.initialDuration ?? lesson.duration,
              ),
            };
          }
          return next;
        }),
      );
    }
    setTimeout(() => {
      resizedRef.current = false;
      suppressDragRef.current = false;
    }, 0);
    previewResizeRef.current = null;
    setResizeState(null);
  };

  useEffect(() => {
    if (!resizeState) return undefined;
    window.addEventListener('mousemove', handleResizeMove);
    window.addEventListener('mouseup', stopResize);
    return () => {
      window.removeEventListener('mousemove', handleResizeMove);
      window.removeEventListener('mouseup', stopResize);
    };
  }, [resizeState]);

  return (
    <div className={`${styles.page} container container--page`}>
      <PageHeader
        className={styles.pageHeader}
        titleClassName={styles.pageTitle}
        subtitleClassName={styles.pageSub}
        title={siteContent.calendar.title}
        subtitle={
          role === 'student'
            ? 'Your personal lesson schedule'
            : `Teacher view — all students (${[...new Set(lessons.map((lesson) => lesson.studentId))].length} students)`
        }
        actions={
          <CalendarHeaderControls
            view={view}
            setView={setView}
            role={role}
            setRole={setRole}
            onCreateLesson={() => openCreateModal(selectedDate ?? today)}
          />
        }
      />

      <div className={styles.calLayout}>
        <div className={styles.calMain}>
          <CalendarMonthNavigator
            monthLabel={`${MONTHS[month]} ${year}`}
            onPrev={() => {
              if (month === 0) {
                setYear((y) => y - 1);
                setMonth(11);
              } else setMonth((m) => m - 1);
            }}
            onNext={() => {
              if (month === 11) {
                setYear((y) => y + 1);
                setMonth(0);
              } else setMonth((m) => m + 1);
            }}
          />

          {view === 'month' && (
            <div className={styles.monthGrid}>
              {DAYS.map((day) => (
                <div key={day} className={styles.dayName}>
                  {day}
                </div>
              ))}
              {Array.from({ length: firstDow }).map((_, i) => (
                <div key={`e${i}`} className={styles.emptyCell} />
              ))}
              {Array.from({ length: daysCount }, (_, i) => {
                const day = i + 1;
                const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                const dayLessons = lessonsOnDate(dateStr).sort(
                  (a, b) => a.startTime.localeCompare(b.startTime) || a.order - b.order,
                );
                const isSelected = selectedDate === dateStr;
                const isToday = dateStr === today;
                const isPastDay = isDateBeforeToday(dateStr);
                return (
                  <div
                    key={day}
                    className={`${styles.dayCell} ${isSelected ? styles.dayCellSelected : ''} ${isToday ? styles.dayCellToday : ''} ${isPastDay ? styles.dayCellPast : ''}`}
                    onClick={() => setSelectedDate(dateStr)}
                    onDoubleClick={() => openCreateModal(dateStr)}
                    onDragOver={(e) => {
                      e.preventDefault();
                      if (!draggingLessonId) return;
                      setMonthGhostDate(dateStr);
                    }}
                    onDrop={(e) => {
                      e.preventDefault();
                      const payload = readLessonDragPayload(e.dataTransfer);
                      const lessonId = payload?.lessonId ?? draggingLessonId;
                      if (!lessonId) return;
                      moveLesson(lessonId, dateStr);
                      setMonthGhostDate(null);
                      setDraggingLessonId(null);
                    }}
                  >
                    <span className={styles.dayNum}>{day}</span>
                    <div className={styles.dayDots}>
                      {dayLessons.slice(0, 3).map((lesson) => (
                        <div
                          key={lesson.id}
                          className={`${styles.dayDot} ${styles[`dot${typeColor[lesson.type]}`]}`}
                        />
                      ))}
                    </div>
                    <div className={styles.dayLessons}>
                    {dayLessons.slice(0, 3).map((lesson) => (
                      (() => {
                        const canDragLesson = canManage && !isLessonInPast(lesson);
                        return (
                      <div
                        key={lesson.id}
                        className={`${styles.dayLessonItem} ${styles[`evt${typeColor[lesson.type]}`]} ${!canDragLesson ? styles.dragDisabled : ''}`}
                        draggable={canDragLesson}
                        onDragStart={(e) => {
                          if (!canDragLesson) {
                            e.preventDefault();
                            return;
                          }
                          writeLessonDragPayload(e.dataTransfer, { lessonId: lesson.id });
                          setDraggingLessonId(lesson.id);
                        }}
                        onDragEnd={() => {
                          setMonthGhostDate(null);
                          setWeekGhost(null);
                          setDraggingLessonId(null);
                        }}
                        onClick={(e) => {
                          e.stopPropagation();
                          if (resizedRef.current) return;
                          openEditModal(lesson);
                        }}
                      >
                        <div className={styles.dayLessonTitle}>
                          {lesson.startTime} {lesson.title}
                        </div>
                      </div>
                        );
                      })()
                    ))}
                    {dayLessons.length > 3 ? <div className={styles.dayMore}>+{dayLessons.length - 3} more</div> : null}
                    {monthGhostDate === dateStr ? (
                      <div className={styles.dayGhostEvent}>Drop lesson here</div>
                    ) : null}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {view === 'week' && (
            <div className={styles.weekView}>
              <div className={styles.weekHeader}>
                <div className={styles.weekTimeCol} />
                {weekDays.map((date) => {
                  const dateStr = toDateString(date);
                  const isToday = dateStr === today;
                  const isSelected = selectedDate === dateStr;
                  const isPastDay = isDateBeforeToday(dateStr);
                  return (
                    <div
                      key={dateStr}
                      className={`${styles.weekDayHeader} ${isToday ? styles.weekDayToday : ''} ${isSelected ? styles.weekDaySelected : ''} ${isPastDay ? styles.weekDayPast : ''}`}
                      onClick={() => setSelectedDate(dateStr)}
                    >
                      <div className={styles.weekDayName}>{DAYS[date.getDay() === 0 ? 6 : date.getDay() - 1]}</div>
                      <div className={styles.weekDayNum}>{date.getDate()}</div>
                    </div>
                  );
                })}
              </div>
              <div className={styles.weekBody}>
                <div className={styles.weekRow} style={{ minHeight: dayColumnHeight }}>
                  <div className={styles.weekHour}>
                    {hourMarks.map((hour) => (
                      <div key={hour} style={{ height: 72 }}>
                        {hour}:00
                      </div>
                    ))}
                  </div>
                  {weekDays.map((date) => {
                    const dateStr = toDateString(date);
                    const dayLessons = weekLessons.filter((lesson) => lesson.date === dateStr);
                    const isPastDay = isDateBeforeToday(dateStr);
                    const passedMinutesToday = isPastDay
                      ? minutesPerDay
                      : dateStr === today
                        ? Math.max(0, Math.min(minutesPerDay, nowMinutes - startHour * 60))
                        : 0;
                    return (
                      <div
                        key={dateStr}
                        className={`${styles.weekCell} ${isPastDay ? styles.weekCellPast : ''}`}
                        style={{ position: 'relative', minHeight: dayColumnHeight }}
                        onDoubleClick={(e) => {
                          const rect = (e.currentTarget as HTMLDivElement).getBoundingClientRect();
                          const minutes = Math.max(
                            0,
                            Math.min(minutesPerDay - 55, Math.round((e.clientY - rect.top) / pxPerMinute / 15) * 15),
                          );
                          const hh = startHour + Math.floor(minutes / 60);
                          const mm = minutes % 60;
                          openCreateModal(dateStr, `${String(hh).padStart(2, '0')}:${String(mm).padStart(2, '0')}`);
                        }}
                        onDragOver={(e) => {
                          e.preventDefault();
                          if (!draggingLessonId) return;
                          const source = lessons.find((lesson) => lesson.id === draggingLessonId);
                          if (!source) return;
                          const rect = (e.currentTarget as HTMLDivElement).getBoundingClientRect();
                          const minutes = Math.max(
                            0,
                            Math.min(minutesPerDay - 55, Math.round((e.clientY - rect.top) / pxPerMinute / 15) * 15),
                          );
                          const hh = startHour + Math.floor(minutes / 60);
                          const mm = minutes % 60;
                          setWeekGhost({
                            lessonId: draggingLessonId,
                            date: dateStr,
                            startTime: `${String(hh).padStart(2, '0')}:${String(mm).padStart(2, '0')}`,
                            duration: source.duration,
                            type: source.type,
                            title: source.title,
                          });
                        }}
                        onDrop={(e) => {
                          e.preventDefault();
                          const payload = readLessonDragPayload(e.dataTransfer);
                          const lessonId = payload?.lessonId ?? draggingLessonId;
                          if (!lessonId) return;
                          const rect = (e.currentTarget as HTMLDivElement).getBoundingClientRect();
                          const minutes = Math.max(
                            0,
                            Math.min(minutesPerDay - 55, Math.round((e.clientY - rect.top) / pxPerMinute / 15) * 15),
                          );
                          const hh = startHour + Math.floor(minutes / 60);
                          const mm = minutes % 60;
                          moveLesson(lessonId, dateStr, `${String(hh).padStart(2, '0')}:${String(mm).padStart(2, '0')}`);
                          setWeekGhost(null);
                          setDraggingLessonId(null);
                        }}
                      >
                        {passedMinutesToday > 0 ? (
                          <div
                            className={styles.weekPastOverlay}
                            style={{ height: passedMinutesToday * pxPerMinute }}
                          />
                        ) : null}
                        {dayLessons.map((lesson) => {
                          const canDragLesson = canManage && !isLessonInPast(lesson);
                          const [hh, mm] = lesson.startTime.split(':').map(Number);
                          const startMinutes = (hh - startHour) * 60 + mm;
                          const top = startMinutes * pxPerMinute;
                          const height = Math.max(55 * pxPerMinute, lesson.duration * pxPerMinute);
                          return (
                            <div
                              key={lesson.id}
                              className={`${styles.weekEvt} ${styles[`evt${typeColor[lesson.type]}`]} ${!canDragLesson ? styles.dragDisabled : ''}`}
                              style={{ position: 'absolute', top, left: 3, right: 3, height }}
                              draggable={canDragLesson}
                              onDragStart={(ev) => {
                                if (!canDragLesson) {
                                  ev.preventDefault();
                                  return;
                                }
                                if (suppressDragRef.current || resizeState) {
                                  ev.preventDefault();
                                  return;
                                }
                                writeLessonDragPayload(ev.dataTransfer, { lessonId: lesson.id });
                                setDraggingLessonId(lesson.id);
                              }}
                              onDragEnd={() => {
                                setMonthGhostDate(null);
                                setWeekGhost(null);
                                setDraggingLessonId(null);
                              }}
                              onClick={() => {
                                if (resizedRef.current) return;
                                openEditModal(lesson);
                              }}
                            >
                              <div
                                style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 6, cursor: 'ns-resize' }}
                                onMouseDown={(ev) => {
                                  ev.stopPropagation();
                                  suppressDragRef.current = true;
                                  setResizeState({
                                    lessonId: lesson.id,
                                    edge: 'top',
                                    originY: ev.clientY,
                                    initialStart: lesson.startTime,
                                    initialDuration: lesson.duration,
                                  });
                                }}
                              />
                              <div className={styles.weekEvtTitle}>{lesson.title}</div>
                              <div className={styles.weekEvtTime}>
                                {lesson.startTime} · {lesson.duration} min
                              </div>
                              <div
                                style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: 6, cursor: 'ns-resize' }}
                                onMouseDown={(ev) => {
                                  ev.stopPropagation();
                                  suppressDragRef.current = true;
                                  setResizeState({
                                    lessonId: lesson.id,
                                    edge: 'bottom',
                                    originY: ev.clientY,
                                    initialStart: lesson.startTime,
                                    initialDuration: lesson.duration,
                                  });
                                }}
                              />
                            </div>
                          );
                        })}
                        {weekGhost && weekGhost.date === dateStr ? (() => {
                          const [ghostH, ghostM] = weekGhost.startTime.split(':').map(Number);
                          const ghostStartMinutes = (ghostH - startHour) * 60 + ghostM;
                          const ghostTop = ghostStartMinutes * pxPerMinute;
                          const ghostHeight = Math.max(55 * pxPerMinute, weekGhost.duration * pxPerMinute);
                          return (
                            <div
                              className={`${styles.weekGhostEvent} ${styles[`evt${typeColor[weekGhost.type]}`]} ${draggingLessonId ? styles.weekGhostEventDragging : ''}`}
                              style={{ top: ghostTop, height: ghostHeight }}
                            >
                              <div className={styles.weekEvtTitle}>{weekGhost.title}</div>
                              <div className={styles.weekEvtTime}>{weekGhost.startTime} · {weekGhost.duration} min</div>
                            </div>
                          );
                        })() : null}
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>

        <SelectedDateSidebar
          selectedDate={selectedDate}
          selectedLessons={selectedLessons}
          role={role}
          typeColor={typeColor}
          typeLabel={typeLabel}
          onEditLesson={(lesson) => openEditModal(lesson)}
        />
      </div>

      {form ? (
        <LessonModal
          mode={modalMode}
          canEdit={canManage}
          form={form}
          onChange={setForm}
          onClose={closeModal}
          canUnlinkSeries={Boolean(editingLesson?.seriesId)}
          onUnlinkSeries={() => setConfirmUnlinkOpen(true)}
          canDeleteLesson={Boolean(editingLesson && canManage)}
          onDeleteLesson={() => setConfirmDeleteOpen(true)}
          onSubmit={submitModal}
          students={visibleStudents}
        />
      ) : null}
      {conflictDialog?.open ? (
        <div className={styles.confirmOverlay} onClick={() => setConflictDialog(null)}>
          <div className={styles.confirmModal} onClick={(e) => e.stopPropagation()}>
            <div className={styles.confirmTitle}>{conflictDialog.title}</div>
            {conflictDialog.message ? <div className={styles.confirmBody}>{conflictDialog.message}</div> : null}
            <div className={styles.confirmSubtitle}>
              {conflictDialog.date} · {conflictDialog.startTime} - {conflictDialog.endTime}
            </div>
            <div className={styles.conflictList}>
              {getConflictingLessons(conflictDialog).map((lesson) => (
                <button
                  key={lesson.id}
                  type="button"
                  className={styles.conflictItem}
                  onClick={() => {
                    setConflictDialog(null);
                    openEditModal(lesson);
                  }}
                >
                  <span>{lesson.title}</span>
                  <span>
                    {lesson.startTime} - {lesson.endTime}
                  </span>
                </button>
              ))}
            </div>
            <div className={styles.confirmActions}>
              <button type="button" className={styles.confirmPrimary} onClick={() => setConflictDialog(null)}>
                Close
              </button>
            </div>
          </div>
        </div>
      ) : null}
      {warningDialog?.open ? (
        <div className={styles.confirmOverlay} onClick={() => setWarningDialog(null)}>
          <div className={styles.confirmModal} onClick={(e) => e.stopPropagation()}>
            <div className={styles.confirmTitle}>{warningDialog.title}</div>
            <div className={styles.confirmBody}>{warningDialog.message}</div>
            <div className={styles.confirmActions}>
              <button type="button" className={styles.confirmPrimary} onClick={() => setWarningDialog(null)}>
                OK
              </button>
            </div>
          </div>
        </div>
      ) : null}
      {confirmDeleteOpen ? (
        <div className={styles.confirmOverlay} onClick={() => setConfirmDeleteOpen(false)}>
          <div className={styles.confirmModal} onClick={(e) => e.stopPropagation()}>
            <div className={styles.confirmTitle}>Delete lesson?</div>
            <div className={styles.confirmBody}>Are you sure you want to delete this lesson? This action cannot be undone.</div>
            <div className={styles.confirmActions}>
              <button type="button" className={styles.confirmSecondary} onClick={() => setConfirmDeleteOpen(false)}>
                Cancel
              </button>
              <button
                type="button"
                className={styles.confirmDanger}
                onClick={() => {
                  if (!editingLesson) return;
                  setLessons((prev) => prev.filter((lesson) => lesson.id !== editingLesson.id));
                  setConfirmDeleteOpen(false);
                  closeModal();
                }}
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      ) : null}
      {confirmUnlinkOpen ? (
        <div className={styles.confirmOverlay} onClick={() => setConfirmUnlinkOpen(false)}>
          <div className={styles.confirmModal} onClick={(e) => e.stopPropagation()}>
            <div className={styles.confirmTitle}>Unlink this lesson from series?</div>
            <div className={styles.confirmBody}>Only this lesson will be detached. Other lessons in series will remain unchanged.</div>
            <div className={styles.confirmActions}>
              <button type="button" className={styles.confirmSecondary} onClick={() => setConfirmUnlinkOpen(false)}>
                Cancel
              </button>
              <button
                type="button"
                className={styles.confirmPrimary}
                onClick={() => {
                  if (!editingLesson) return;
                  setLessons((prev) =>
                    prev.map((lesson) =>
                      lesson.id === editingLesson.id
                        ? {
                            ...lesson,
                            seriesId: undefined,
                            recurrence: 'none',
                            weeklyDays: [],
                          }
                        : lesson,
                    ),
                  );
                  setEditingLesson((prev) =>
                    prev
                      ? {
                          ...prev,
                          seriesId: undefined,
                          recurrence: 'none',
                          weeklyDays: [],
                        }
                      : prev,
                  );
                  setForm((prev) =>
                    prev
                      ? {
                          ...prev,
                          recurrence: 'none',
                          weeklyDays: [],
                          applyToSeries: false,
                        }
                      : prev,
                  );
                  setConfirmUnlinkOpen(false);
                }}
              >
                Unlink
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );
}
