'use client';

import type { ScheduledLessonDto } from '@soenglish/shared-types';
import { Button, CalendarEventCard, SegmentedControl, SurfaceCard } from '../../components/ui';
import { canSchedule, type UserRole } from '../../mocks';
import styles from './page.module.scss';

export function CalendarHeaderControls({
  view,
  setView,
  role,
  setRole,
  onCreateLesson,
}: {
  view: 'month' | 'week';
  setView: (view: 'month' | 'week') => void;
  role: UserRole;
  setRole: (role: UserRole) => void;
  onCreateLesson: () => void;
}) {
  return (
    <div className={styles.headerRight}>
      <SegmentedControl
        value={view}
        onValueChange={setView}
        ariaLabel="Calendar view"
        className={styles.viewToggle}
        optionClassName={styles.viewBtn}
        activeOptionClassName={styles.viewActive}
        options={[
          { value: 'month', label: 'Month' },
          { value: 'week', label: 'Week' },
        ]}
      />
      <SegmentedControl
        value={role}
        onValueChange={setRole}
        ariaLabel="Calendar role"
        className={styles.roleToggle}
        optionClassName={styles.roleBtn}
        activeOptionClassName={styles.roleActive}
        options={[
          { value: 'student', label: 'Student' },
          { value: 'teacher', label: 'Teacher' },
          { value: 'admin', label: 'Admin' },
          { value: 'super-admin', label: 'Super Admin' },
        ]}
      />
      <Button type="button" className={styles.createLessonBtn} onClick={onCreateLesson}>
        Create lesson
      </Button>
    </div>
  );
}

export function SelectedDateSidebar({
  selectedDate,
  selectedLessons,
  role,
  typeColor,
  typeLabel,
  onEditLesson,
}: {
  selectedDate: string | null;
  selectedLessons: ScheduledLessonDto[];
  role: UserRole;
  typeColor: Record<string, string>;
  typeLabel: Record<string, string>;
  onEditLesson: (lesson: ScheduledLessonDto) => void;
}) {
  return (
    <div className={styles.calSidebar}>
      <SurfaceCard className={styles.sidePanel}>
        <div className={styles.sidePanelTitle}>
          {selectedDate
            ? new Date(`${selectedDate}T12:00:00`).toLocaleDateString('en-GB', {
                weekday: 'long',
                day: 'numeric',
                month: 'long',
              })
            : 'Select a date'}
        </div>
        {selectedLessons.length === 0 && selectedDate ? <div className={styles.noEvents}>No lessons scheduled</div> : null}
        {selectedLessons.map((lesson) => (
          <CalendarEventCard
            key={lesson.id}
            className={`${styles.eventCard} ${styles[`evt${typeColor[lesson.type]}`]}`}
            headerClassName={styles.evtHeader}
            typeClassName={styles.evtType}
            statusClassName={`${styles.evtStatus} ${lesson.status === 'completed' ? styles.statusConfirmed : styles.statusPending}`}
            titleClassName={styles.evtTitle}
            metaClassName={styles.evtMeta}
            teacherClassName={styles.evtTeacher}
            actionsClassName={styles.evtActions}
            actionButtonClassName={styles.rescheduleBtn}
            typeLabel={typeLabel[lesson.type]}
            typeVariant={lesson.type === 'vocabulary' ? 'green' : lesson.type === 'speaking' ? 'amber' : 'blue'}
            statusLabel={lesson.status}
            statusVariant={lesson.status === 'completed' ? 'green' : 'amber'}
            title={lesson.title}
            time={lesson.startTime}
            teacherName={lesson.teacherName}
            actionLabel={canSchedule('calendar', role) ? 'Edit lesson' : 'Request change'}
            onAction={() => onEditLesson(lesson)}
          />
        ))}
      </SurfaceCard>
    </div>
  );
}

export function CalendarMonthNavigator({
  monthLabel,
  onPrev,
  onNext,
}: {
  monthLabel: string;
  onPrev: () => void;
  onNext: () => void;
}) {
  return (
    <div className={styles.calNav}>
      <Button type="button" className={styles.navBtn} onClick={onPrev}>←</Button>
      <h2 className={styles.calMonthTitle}>{monthLabel}</h2>
      <Button type="button" className={styles.navBtn} onClick={onNext}>→</Button>
    </div>
  );
}
